"""family_gw2_f16: SAFE fp16 rebuilds of still-FLOAT memory-dominated incumbents.

Each embedded incumbent (out_full) had every FLOAT32 intermediate lowered to FLOAT16
(Cast input->f16 at top, all FLOAT initializers/Constants->f16, f16 free output).
fp16 is bit-identical here: every float intermediate is <=2048 and fp16-representable,
verified (representability + magnitude) over train+test+ALL arc-gen. Routed by a hash of
the task's train pairs; both the fp16 rebuild and the original incumbent are proposed so
the grader keeps whichever is cheaper (never a regression)."""
import base64, gzip, hashlib, json
import onnx

def _d(s):
    return onnx.load_model_from_string(gzip.decompress(base64.b64decode(s)))

# fingerprint(train) -> (taskid, fp16_b64, orig_b64)
_E = {
  "c48a662904d59970f46d0d34b63a0424": (158, "", ""),
  "0e28e71d5b7f5a1fe37aef299a256c41": (285, "", ""),
  "e1ae71538445bc6e6681bc2b0cec4365": (54, "", ""),
  "4f6ae8f48721ddc545160093d5318880": (23, "", ""),
  "0f85c938dcf3d30c5c6b4972954332ba": (76, "", ""),
  "b98b27b4ef5dd741203896444defecee": (80, "", ""),
  "43262f7f0c1341a5ef85f61db8d376f3": (349, "", ""),
  "c14477d61ded6f99fe5b872375a1903e": (118, "", ""),
  "eeca419a9ebfcc7b2b08127739f96a10": (367, "", ""),
  "b25f1c366b47c86117632bd7a196d5a2": (5, "", ""),
  "aa80eb96121597deeed314198f9f93fa": (157, "", ""),
  "b14619932e359bf6c081afa8394cf977": (44, "", ""),
  "3eaa356139adbddd2acc5ad33971f170": (264, "", ""),
}

def _fp(train):
    return hashlib.md5(json.dumps(train, sort_keys=True).encode()).hexdigest()

def candidates(examples):
    e = _E.get(_fp(examples.get('train', [])))
    if not e:
        return []
    tid, a, b = e
    return [(f'gw2f16_{tid}', _d(a)), (f'gw2orig_{tid}', _d(b))]
